sys_script_email.script:
(function runMailScript( /* GlideRecord */ current, /* TemplatePrinter */ template,
    /* Optional EmailOutbound */
    email, /* Optional GlideRecord */ email_action,
    /* Optional GlideRecord */
    event) {

    // 1. Fetch the Sys ID of the selected workspace record from your variable
    // Make sure 'select_workspace' exactly matches your workspace catalog variable name!
    var workspaceSysId = current.variables.select_workspace;

    if (workspaceSysId) {
        var roomGr = new GlideRecord('x_1534869_wrm_workspace_options'); // Change to your workspace table name if different
        if (roomGr.get(workspaceSysId)) {

            var maxOcc = roomGr.getValue('max_occupancy'); // Replace 'max_occupancy' with its exact column backend name

            // 3. Print the text layouts directly into your email body frame         
            // if (maxOcc) {
            //     template.print('• <b>Max Occupancy:</b> ' + maxOcc + '<br />');
            // }
            if (maxOcc) {
                template.print(maxOcc);
            }
        }
    }

})(current, template, email, email_action, event);
